// ── Validate and enrich incoming calendar request ──────────────────────────
const body = $input.first().json.body || $input.first().json;

const required = ['mission_id', 'mission_title', 'entity', 'requested_by_agent', 'scheduling_reason'];
const missing = required.filter(k => !body[k]);
if (missing.length) {
  return [{ json: { ok: false, error: 'Missing required fields: ' + missing.join(', '), body } }];
}

// Derive a suggested start time if not provided
// Default: next business day at 9AM Eastern
function nextBusinessDay9AM() {
  const now = new Date();
  const est = new Date(now.toLocaleString('en-US', { timeZone: 'America/New_York' }));
  let d = new Date(est);
  d.setDate(d.getDate() + 1);
  while (d.getDay() === 0 || d.getDay() === 6) { d.setDate(d.getDate() + 1); }
  d.setHours(9, 0, 0, 0);
  return d.toISOString();
}

const duration = body.preferred_duration_minutes || 60;
const suggestedStart = body.suggested_time_window || nextBusinessDay9AM();
const suggestedEnd   = new Date(new Date(suggestedStart).getTime() + duration * 60000).toISOString();

const priorityLabel = {
  CRITICAL: '🔴 CRITICAL',
  HIGH:     '🟠 HIGH',
  MEDIUM:   '🟡 MEDIUM',
  LOW:      '🟢 LOW',
}[body.priority] || body.priority || 'MEDIUM';

const eventTitle = '[KAI] ' + body.entity + ' · ' + body.mission_title.slice(0, 60);
const eventDescription = [
  'Mission ID: ' + body.mission_id,
  'Requested by: ' + body.requested_by_agent + ' → Aidan',
  'Entity: ' + body.entity,
  'Priority: ' + priorityLabel,
  'Reason: ' + body.scheduling_reason,
  body.deadline ? 'Deadline: ' + body.deadline : null,
].filter(Boolean).join('\n');

return [{ json: {
  ok: true,
  mission_id:        body.mission_id,
  mission_title:     body.mission_title,
  entity:            body.entity,
  requested_by_agent: body.requested_by_agent,
  scheduling_reason: body.scheduling_reason,
  priority:          body.priority || 'MEDIUM',
  deadline:          body.deadline || null,
  preferred_duration_minutes: duration,
  suggested_start:   suggestedStart,
  suggested_end:     suggestedEnd,
  event_title:       eventTitle,
  event_description: eventDescription,
  calendar_id:       'primary',
} }];

// ── Build calendar_block object for mission mutation ────────────────────────
const input    = $('Validate + Enrich Request').first().json;
const calEvent = $input.first().json;

const calBlock = {
  mission_id:          input.mission_id,
  agent_requesting:    input.requested_by_agent,
  purpose:             input.scheduling_reason,
  scheduled_start:     calEvent.start?.dateTime || input.suggested_start,
  scheduled_end:       calEvent.end?.dateTime   || input.suggested_end,
  duration_minutes:    input.preferred_duration_minutes,
  calendar_event_id:   calEvent.id || null,
  calendar_status:     calEvent.id ? 'SCHEDULED' : 'PENDING',
  scheduling_notes:    calEvent.htmlLink ? 'Event created: ' + calEvent.htmlLink : 'Event created',
  follow_up_required:  true,
  created_by:          'Aidan',
  created_at:          new Date().toISOString(),
};

return [{ json: {
  ok:                  true,
  mission_id:          input.mission_id,
  calendar_status:     calBlock.calendar_status,
  calendar_event_id:   calBlock.calendar_event_id,
  scheduled_start:     calBlock.scheduled_start,
  scheduled_end:       calBlock.scheduled_end,
  scheduling_notes:    calBlock.scheduling_notes,
  calendar_block:      calBlock,
  // For mission mutation
  mission_update: {
    calendar_blocks: [calBlock],
  },
  mission_event: {
    agent:     'Aidan',
    action:    'calendar_block_created',
    note:      'Block: ' + calBlock.scheduled_start.slice(0,16) + ' · ' + input.scheduling_reason.slice(0,60) + ' · via ' + input.requested_by_agent,
    timestamp: new Date().toISOString(),
  },
} }];

// ── Compose final success response ──────────────────────────────────────────
const block  = $('Build Calendar Block').first().json;
const write  = $input.first().json;

return [{ json: {
  ok:                true,
  mission_id:        block.mission_id,
  calendar_status:   block.calendar_status,
  calendar_event_id: block.calendar_event_id,
  scheduled_start:   block.scheduled_start,
  scheduled_end:     block.scheduled_end,
  scheduling_notes:  block.scheduling_notes,
  mission_updated:   write.ok === true,
} }];

const input = $('Validate + Enrich Request').first().json;
return [{ json: {
  ok:              false,
  mission_id:      input.mission_id || null,
  calendar_status: 'ERROR',
  calendar_event_id: null,
  scheduled_start:   null,
  scheduled_end:     null,
  scheduling_notes:  input.error || 'Validation failed',
} }];
